<?php
 namespace WPAICG\Chat\Storage; use WPAICG\Chat\Admin\AdminSetup; use WP_Error; if (!defined('ABSPATH')) { exit; } class BotStorage { private $lifecycle_manager; private $settings_manager; private $default_setup; private $site_wide_manager; public function __construct() { $lifecycle_path = __DIR__ . '/class-aipkit_bot_lifecycle_manager.php'; $settings_path = __DIR__ . '/class-aipkit_bot_settings_manager.php'; $default_setup_path = __DIR__ . '/class-aipkit_default_bot_setup.php'; $site_wide_path = __DIR__ . '/class-aipkit_site_wide_bot_manager.php'; $admin_setup_path = WPAICG_PLUGIN_DIR . 'classes/chat/admin/chat_admin_setup.php'; $settings_getter_path = __DIR__ . '/class-aipkit-bot-settings-getter.php'; if (file_exists($admin_setup_path) && !class_exists(AdminSetup::class)) { require_once $admin_setup_path; } if (file_exists($default_setup_path) && !class_exists(DefaultBotSetup::class)) { require_once $default_setup_path; } if (file_exists($site_wide_path) && !class_exists(SiteWideBotManager::class)) { require_once $site_wide_path; } if (file_exists($lifecycle_path) && !class_exists(BotLifecycleManager::class)) { require_once $lifecycle_path; } if (file_exists($settings_path) && !class_exists(BotSettingsManager::class)) { require_once $settings_path; } if (file_exists($settings_getter_path) && !class_exists(AIPKit_Bot_Settings_Getter::class)) { require_once $settings_getter_path; } if (class_exists(DefaultBotSetup::class)) { $this->default_setup = new DefaultBotSetup(); } if (class_exists(SiteWideBotManager::class)) { $this->site_wide_manager = new SiteWideBotManager(); } if (class_exists(BotLifecycleManager::class)) { $this->lifecycle_manager = new BotLifecycleManager(); } if (class_exists(BotSettingsManager::class)) { $this->settings_manager = new BotSettingsManager(); } } public function get_chatbots(bool $prefetch_meta = true): array { if (!class_exists(AdminSetup::class)) { return []; } $args = array( 'post_type' => AdminSetup::POST_TYPE, 'post_status' => 'publish', 'posts_per_page' => -1, 'orderby' => 'title', 'order' => 'ASC', 'update_post_meta_cache' => $prefetch_meta, 'update_post_term_cache' => false, ); $query = new \WP_Query($args); return $query->get_posts(); } public function get_chatbots_with_settings(): array { $bot_posts = $this->get_chatbots(); if (empty($bot_posts)) { return []; } $bots_with_settings = []; foreach ($bot_posts as $bot_post) { $all_meta_for_bot = get_post_meta($bot_post->ID); $prefetched_meta = []; if (is_array($all_meta_for_bot)) { foreach ($all_meta_for_bot as $meta_key => $meta_values) { $prefetched_meta[$meta_key] = isset($meta_values[0]) ? $meta_values[0] : null; } } if (!class_exists(AIPKit_Bot_Settings_Getter::class)) { continue; } $settings = AIPKit_Bot_Settings_Getter::get($bot_post->ID, $prefetched_meta); if (!is_wp_error($settings)) { $bots_with_settings[] = [ 'post' => $bot_post, 'settings' => $settings, ]; } } return $bots_with_settings; } public function create_bot(string $botName): array|WP_Error { if (!$this->lifecycle_manager) { return new WP_Error('init_error', 'Lifecycle Manager not available.'); } return $this->lifecycle_manager->create_bot($botName); } public function save_bot_settings(int $botId, array $settings): bool|WP_Error { if (!$this->settings_manager) { return new WP_Error('init_error', 'Settings Manager not available.'); } return $this->settings_manager->save_bot_settings($botId, $settings); } public function delete_bot(int $botId): bool|WP_Error { if (!$this->lifecycle_manager) { return new WP_Error('init_error', 'Lifecycle Manager not available.'); } return $this->lifecycle_manager->delete_bot($botId); } public function get_chatbot_settings(int $bot_id): array { if (!$this->settings_manager) { return []; } $settings = $this->settings_manager->get_chatbot_settings($bot_id); if (is_wp_error($settings) || !is_array($settings)) { return []; } return $settings; } public function get_site_wide_bot_id(bool $force_refresh = false): ?int { if (!$this->site_wide_manager) { return null; } return $this->site_wide_manager->get_site_wide_bot_id($force_refresh); } public function ensure_default_chatbot(): void { if (!$this->default_setup) { return; } DefaultBotSetup::ensure_default_chatbot(); } } 